import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 19 — Undo / Redo","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/19-undo-redo.md","filePath":"chapters/19-undo-redo.md"}'),o={name:"chapters/19-undo-redo.md"};function i(d,e,r,h,l,c){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="chapter-19-—-undo-redo" tabindex="-1">Chapter 19 — Undo / Redo <a class="header-anchor" href="#chapter-19-—-undo-redo" aria-label="Permalink to &quot;Chapter 19 — Undo / Redo&quot;">​</a></h1><blockquote><p><em>&quot;Mistakes are inevitable. Undo is essential.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Vim&#39;s undo system is more powerful than most editors.</p><p>It supports:</p><ul><li>Multiple undo levels</li><li>Redo</li><li>Branching undo (you can undo a redo)</li><li>Time-based undo</li></ul><hr><h1 id="basic-undo-redo" tabindex="-1">Basic Undo / Redo <a class="header-anchor" href="#basic-undo-redo" aria-label="Permalink to &quot;Basic Undo / Redo&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>u</code></td><td>Undo last change</td></tr><tr><td><code>Ctrl+r</code></td><td>Redo last undone change</td></tr><tr><td><code>U</code></td><td>Undo all changes on current line</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Make a change: type i, add text, Esc</span></span>
<span class="line"><span>Press u        →   undoes that change</span></span>
<span class="line"><span>Press Ctrl+r   →   redoes that change</span></span>
<span class="line"><span>Press u        →   undoes it again</span></span></code></pre></div><h2 id="with-counts" tabindex="-1">With Counts <a class="header-anchor" href="#with-counts" aria-label="Permalink to &quot;With Counts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3u          →   undo last 3 changes</span></span>
<span class="line"><span>5Ctrl+r     →   redo last 5 undone changes</span></span></code></pre></div><hr><h1 id="what-counts-as-a-change" tabindex="-1">What Counts as a Change? <a class="header-anchor" href="#what-counts-as-a-change" aria-label="Permalink to &quot;What Counts as a Change?&quot;">​</a></h1><p>Vim groups certain actions into a single &quot;change&quot;:</p><ul><li>Everything between entering and leaving insert mode is one change.</li><li>Each command in normal mode is one change.</li></ul><p>So typing an entire paragraph in insert mode can be undone with one <code>u</code>.</p><hr><h1 id="the-undo-tree" tabindex="-1">The Undo Tree <a class="header-anchor" href="#the-undo-tree" aria-label="Permalink to &quot;The Undo Tree&quot;">​</a></h1><p>Vim doesn&#39;t just have an undo history line — it has an <strong>undo tree</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Change 1 ← Change 2 ← Change 3</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>                      Change 4 (branch)</span></span></code></pre></div><p>If you undo back to Change 2, then make a new change, it creates a branch.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Change 1 ← Change 2 ← Change 3</span></span>
<span class="line"><span>                           ↓</span></span>
<span class="line"><span>                      Change 2 ← Change 5 (new branch)</span></span></code></pre></div><h2 id="navigating-the-undo-tree" tabindex="-1">Navigating the Undo Tree <a class="header-anchor" href="#navigating-the-undo-tree" aria-label="Permalink to &quot;Navigating the Undo Tree&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:undo 3</code></td><td>Undo to change number 3</td></tr><tr><td><code>g-</code></td><td>Go to older change in tree</td></tr><tr><td><code>g+</code></td><td>Go to newer change in tree</td></tr></tbody></table><hr><h1 id="persistent-undo" tabindex="-1">Persistent Undo <a class="header-anchor" href="#persistent-undo" aria-label="Permalink to &quot;Persistent Undo&quot;">​</a></h1><p>Vim can save undo history between sessions.</p><p>Enable it in your config:</p><div class="language-vim vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vim</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> undofile</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> undodir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=~</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">/.vim/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">undo</span></span></code></pre></div><p>This lets you undo changes even after closing and reopening a file.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>u</code></td><td>Undo</td></tr><tr><td><code>Ctrl+r</code></td><td>Redo</td></tr><tr><td><code>U</code></td><td>Undo all line changes</td></tr><tr><td><code>g-</code></td><td>Go to older in tree</td></tr><tr><td><code>g+</code></td><td>Go to newer in tree</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>u</code> undoes, <code>Ctrl+r</code> redoes.</li><li>Insert mode typing is one undoable change.</li><li>Vim has an undo tree, not just a linear history.</li><li><code>:undofile</code> enables persistent undo across sessions.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Make several edits and undo them one by one with <code>u</code>.</li><li>Redo them with <code>Ctrl+r</code>.</li><li>Undo all changes on a single line with <code>U</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./20-replace.html"><strong>Chapter 20 — Replace</strong></a></p><p>Replace characters and text patterns in Vim.</p>`,48)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
